.darma-loader-darma-custom-105 {
  width: 40px;
  aspect-ratio: 1;
  position: relative;
}
.darma-loader-darma-custom-105:before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 50%;
  --c:#0000, var(--loader-color, #f03355) 1deg 120deg,#0000 121deg;
  background:
    conic-gradient(from 0deg,  var(--c)) top right,
    conic-gradient(from 120deg,var(--c)) bottom,
    conic-gradient(from 240deg,var(--c)) top left;
  background-size: 40px 40px;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-105-l25 2s infinite cubic-bezier(0.3,1,0,1);
}
@keyframes darma-loader-darma-custom-105-l25 {
   33%  {inset:-8px;transform: rotate(0deg)}
   66%  {inset:-8px;transform: rotate(180deg)}
   100% {inset:0   ;transform: rotate(180deg)}
}

